import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { Chart as ChartJS, CategoryScale, LinearScale, BarElement, Title, ArcElement, Tooltip, Legend } from 'chart.js';
import { Bar, Pie } from 'react-chartjs-2';

import URL from '@/constants/url';
import { default as EgovLeftNav } from '@/components/leftmenu/EgovLeftNavAdmin';
import { requestFetch, getQueryString } from '@/api/egovFetch';

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, ArcElement, Tooltip, Legend);

const barChartOptions = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { position: 'top' },
    title: { display: true, text: '앱별 이용 현황' },
  },
};

const pieChartOptions = {
  responsive: true,
  maintainAspectRatio: false,
};

function EgovAdminMenuStatList() {
  const [barChartData, setBarChartData] = useState({ datasets: [] });
  const [pieChartData, setPieChartData] = useState({ datasets: [] });
  const [menuStats, setMenuStats] = useState([]);
  const [total, setTotal] = useState(0);
  const [searchCondition, setSearchCondition] = useState({
    searchWrd: '',
    startDate: '',
    endDate: ''
  });

  const fetchData = useCallback((params) => {
    requestFetch(`/menuStat${getQueryString(params)}`, { method: 'GET' }, (response) => {
      const { result } = response;
      if (result && result.resultList) {
        const resultList = result.resultList;
        const labels = resultList.map(item => item.menuNm);
        const data = resultList.map(item => item.count);

        setBarChartData({
          labels,
          datasets: [
            {
              label: '앱별 접속 수',
              data,
              backgroundColor: 'rgba(53, 162, 235, 0.5)'
            },
          ],
        });

        setPieChartData({
          labels,
          datasets: [
            {
              label: '앱별 접속 수',
              data,
              backgroundColor: [
                'rgba(255, 99, 132, 0.2)', 'rgba(54, 162, 235, 0.2)', 'rgba(255, 206, 86, 0.2)',
                'rgba(75, 192, 192, 0.2)', 'rgba(153, 102, 255, 0.2)', 'rgba(255, 159, 64, 0.2)',
                'rgba(255, 99, 132, 0.2)', 'rgba(54, 162, 235, 0.2)', 'rgba(255, 206, 86, 0.2)',
                'rgba(75, 192, 192, 0.2)', 'rgba(153, 102, 255, 0.2)',
              ],
              borderColor: [
                'rgba(255, 99, 132, 1)', 'rgba(54, 162, 235, 1)', 'rgba(255, 206, 86, 1)',
                'rgba(75, 192, 192, 1)', 'rgba(153, 102, 255, 1)', 'rgba(255, 159, 64, 1)',
                'rgba(255, 99, 132, 1)', 'rgba(54, 162, 235, 1)', 'rgba(255, 206, 86, 1)',
                'rgba(75, 192, 192, 1)', 'rgba(153, 102, 255, 1)',
              ],
              borderWidth: 1,
            },
          ],
        });
        setMenuStats(resultList);
        setTotal(resultList.reduce((acc, cur) => acc + cur.count, 0));
      }
    });
  }, []);

  useEffect(() => {
    fetchData({ pageIndex: 1, searchCnd: '0', searchWrd: '' });
  }, [fetchData]);

  const handleSearchConditionChange = (e) => {
    setSearchCondition({ ...searchCondition, [e.target.id]: e.target.value });
  };

  const handleSearch = () => {
    const params = {
      pageIndex: 1,
      searchCnd: '0',
      searchWrd: searchCondition.searchWrd,
      startDate: searchCondition.startDate,
      endDate: searchCondition.endDate,
    };
    fetchData(params);
  };

  return (
    <div id="new_wrap2">
      <div className="mid_wrap d_flex d_jcc">
        <div className="w1200">
          {/* 네비게이션 영역 */}
          <div className="nav_wrap d_flex d_end">
            <div className="nav d_flex d_end">
              <Link to={URL.MAIN}><div className="nav_ico img_all"></div></Link>
              <div className="nav_ico_arr img_all"></div>
              <Link to={URL.ADMIN}><div className="nav_txt">시스템 운영관리</div></Link>
              <div className="nav_ico_arr img_all"></div>
              <Link><div className="nav_txt">앱별 이용 현황</div></Link>
            </div>
          </div>

          {/* 제목 및 검색창 영역 (밝은 배경 위에 위치) */}
          <div>
            <h1 className="txt_cen">앱별 이용 현황</h1>
            <div className="mid_find d_flex d_jcc aic gap20">
              <label htmlFor="searchWrd" className="font20">앱명</label>
              <input type="search" id="searchWrd" className="w390" placeholder="메뉴명을 입력하세요"
                value={searchCondition.searchWrd}
                onChange={handleSearchConditionChange}
                onKeyDown={(e) => {
                  // 엔터 키로 검색 기능 추가
                  if (e.key === 'Enter') {
                    handleSearch();
                  }
                }} />

              <label className="font20" htmlFor='startDate'>검색 기간</label>
              <input type="date" id="startDate" className="w210" value={searchCondition.startDate} onChange={handleSearchConditionChange} />
              ~
              <input type="date" id="endDate" className="w210" value={searchCondition.endDate} onChange={handleSearchConditionChange} />
              <button type="button" className="blu_btn" onClick={handleSearch}>조 회</button>
            </div>
          </div>
        </div>
      </div>
      <div className="bor_wrap d_flex d_jcc">
        <div className="w1200">

          {/* 통계표 (app_wrap2) */}
          <div className="app_wrap2" style={{ marginTop: '10px', overflowX: 'hidden' }}>
            <div className="pers_title d_flex d_jcsa aic" style={{ minWidth: '1250px', marginTop:'40px' }}>
              {menuStats.map(stat => (
                <div className="app_txt1 exbold font20" key={stat.menuCd}>{stat.menuNm}</div>
              ))}
              <div className="app_txt1 exbold font20">합계</div>
            </div>
            <div className="pers_result d_flex d_jcsa aic" style={{ minWidth: '1250px' }}>
              {menuStats.map(stat => (
                <div className="pers_txt" key={stat.menuCd}>{stat.count.toLocaleString()}</div>
              ))}
              <div className="pers_txt">{total.toLocaleString()}</div>
            </div>
          </div>

          {/* 그래프 (graph_wrap) */}
          <div className="graph_wrap" style={{paddingBottom:'45px' }}>
            <div style={{ display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', width: '100%' }}>
              <div style={{ width: '75%', height: '350px' }}>
                {barChartData.datasets.length > 0 && <Bar options={barChartOptions} data={barChartData} />}
              </div>
              <div style={{ width: '25%', height: '350px' }}>
                {pieChartData.datasets.length > 0 && <Pie options={pieChartOptions} data={pieChartData} />}
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

export default EgovAdminMenuStatList;

