  label?: string;
  data: number[];
  backgroundColor?: string | string[];
  borderColor?: string[];
  borderWidth?: number;
}

interface ChartData {
  labels?: string[];
  datasets: ChartDataset[];
}

interface MenuStat {
  menuCd: string;
  menuNm: string;
  count: number;
}

interface SearchCondition {
  searchWrd: string;
  startDate: string;
  endDate: string;
}

interface FetchParams {
  pageIndex: number;
  searchCnd: string;
  searchWrd: string;
  startDate?: string;
  endDate?: string;
}

const barChartOptions = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { position: 'top' as const },
    title: { display: true, text: '앱별 이용 현황' },
  },
};

const pieChartOptions = {
  responsive: true,
  maintainAspectRatio: false,
};

