loader.config({ monaco });

function EgovAdminCatalogEdit() {
  console.group("EgovAdminCatalogEdit");
  console.log("[Start] EgovAdminCatalogEdit ------------------------------");

  const navigate = useNavigate();
  const location = useLocation();
  const ctlgNo = location.state?.ctlgNo || "";

  const editorRef = useRef(null);
  const [detail, setDetail] = useState({});
  const [editorValue, setEditorValue] = useState("");
  const [errorMsg, setErrorMsg] = useState("");

  const retrieveDetail = useCallback(() => {
    if (!ctlgNo) {
      navigate({ pathname: URL.ERROR }, { state: { msg: "카탈로그 번호가 없습니다." } });
      return;
    }

    // 1) 메타(ctlgNm/updDt 등)는 기존 ResultVO 엔드포인트에서 조회.
    //    (ctlgJson 은 전역 Jackson XSS escape 로 깨지므로 여기서 쓰지 않는다.)
    const metaURL = `/admin/catalog/${ctlgNo}`;
    const metaOptions = {
      method: "GET",
      headers: {
        "Content-type": "application/json",
      },
    };
    EgovNet.requestFetch(metaURL, metaOptions, (resp) => {
      if (Number(resp.resultCode) === Number(CODE.RCV_SUCCESS) && resp.result?.catalogVO) {
        setDetail(resp.result.catalogVO);
      } else {
        navigate({ pathname: URL.ERROR }, { state: { msg: resp.resultMessage } });
      }
    });

    // 2) Monaco 에 실을 본문은 raw JSON 엔드포인트에서 원문 그대로 로드.
    //    StringHttpMessageConverter 경로라 escape 가 걸리지 않은 clean JSON 이 온다.
    const jsonURL = `/admin/catalog/${ctlgNo}/json`;
    const jsonOptions = {
      method: "GET",
      headers: {
        Accept: "application/json",
      },
    };
    EgovNet.requestFetchText(
      jsonURL,
      jsonOptions,
      (text, response) => {
        if (response && response.ok) {
          // 가독성을 위해 로드 시 들여쓰기(pretty-print)로 표시.
          // (DB의 ctlg_json::text 는 한 줄이라 그대로 두면 가독성이 떨어짐)
          let display = text || "";
          try {
            display = JSON.stringify(JSON.parse(display), null, 2);
          } catch {
            // 파싱 불가하면 원문 그대로 보여준다(편집해서 고칠 수 있도록).
          }
          setEditorValue(display);
        } else if (response && response.status === 404) {
          setErrorMsg("본문(JSON)을 찾을 수 없습니다. (ctlgNo=" + ctlgNo + ")");
        } else {
          setErrorMsg("본문(JSON) 로드 실패 (HTTP " + (response ? response.status : "?") + ")");
        }
      },
      (err) => {
        setErrorMsg("본문(JSON) 로드 중 오류: " + (err?.message || err));
      }
    );
  }, [ctlgNo, navigate]);

  useEffect(() => {
    retrieveDetail();
  }, [retrieveDetail]);

  const handleEditorMount = (editor) => {
    editorRef.current = editor;
  };

  // 포맷(prettify) — 클라이언트측 JSON.parse 로 정렬. 깨졌으면 에러 표시.
  const handlePrettify = () => {
    const current = editorRef.current ? editorRef.current.getValue() : editorValue;
    try {
      const obj = JSON.parse(current);
      const pretty = JSON.stringify(obj, null, 2);
      setEditorValue(pretty);
      if (editorRef.current) editorRef.current.setValue(pretty);
      setErrorMsg("");
    } catch (e) {
      setErrorMsg("JSON 포맷 실패 — 유효하지 않은 JSON 입니다: " + e.message);
    }
  };

  const handleSave = () => {
    const current = editorRef.current ? editorRef.current.getValue() : editorValue;

    // 1) 클라이언트측 JSON.parse 사전검증 + 저장 본문은 압축(minify: 줄바꿈/공백 제거)
    let minified;
    try {
      minified = JSON.stringify(JSON.parse(current));
    } catch (e) {
      setErrorMsg("저장 불가 — 유효하지 않은 JSON 입니다: " + e.message);
      return;
    }
    setErrorMsg("");

    const saveURL = `/admin/catalog/${ctlgNo}`;
    const requestOptions = {
      method: "POST",
      headers: {
        // 압축된 JSON 본문 전송(서버는 String 으로 받아 parse 검증 후 jsonb 저장).
        "Content-type": "application/json",
      },
