    };

    EgovNet.requestFetch(saveURL, requestOptions, (resp) => {
      if (Number(resp.resultCode) === Number(CODE.RCV_SUCCESS)) {
        alert("성공적으로 저장되었습니다.");
        navigate({ pathname: URL.ADMIN_CATALOG });
      } else {
        // 서버측 JSON 검증/대상없음 등 오류 메시지 표시
        setErrorMsg("저장 실패: " + resp.resultMessage);
      }
    });
  };

  console.log("------------------------------EgovAdminCatalogEdit [End]");
  console.groupEnd("EgovAdminCatalogEdit");

  return (
    <div className="wrap">
      <div className="mid_wrap d_flex d_jcc">
        <div className="w1200">
          <div className="nav_wrap d_flex d_end">
            <div className="nav d_flex d_end">
              <Link to={URL.MAIN}>
                <div className="nav_ico img_all"></div>
              </Link>
              <div className="nav_ico_arr img_all"></div>
              <Link to={URL.ADMIN}>
                <div className="nav_txt">시스템 운영관리</div>
              </Link>
              <div className="nav_ico_arr img_all"></div>
              <Link to={URL.ADMIN_CATALOG}>
                <div className="nav_txt">카탈로그(init JSON) 관리</div>
              </Link>
              <div className="nav_ico_arr img_all"></div>
              <Link>
                <div className="nav_txt">편집</div>
              </Link>
            </div>
          </div>

          <div>
            <h1 className="txt_cen">카탈로그(init JSON) 편집</h1>

            <div className="d_flex aic" style={{ gap: "12px", margin: "12px 0" }}>
              <span className="font20">카탈로그 번호: {detail.ctlgNo}</span>
              <span className="font20">명칭: {detail.ctlgNm}</span>
            </div>

            {errorMsg && (
              <div
                style={{
                  color: "#c00",
                  background: "#fff3f3",
                  border: "1px solid #f5b5b5",
                  padding: "8px 12px",
                  margin: "8px 0",
                  whiteSpace: "pre-wrap",
                }}
              >
                {errorMsg}
              </div>
            )}

            <div style={{ border: "1px solid #ccc" }}>
              <Editor
                height="600px"
                defaultLanguage="json"
                language="json"
                value={editorValue}
                onMount={handleEditorMount}
                onChange={(value) => setEditorValue(value ?? "")}
                options={{
                  minimap: { enabled: false },
                  fontSize: 13,
                  tabSize: 2,
                  scrollBeyondLastLine: false,
                  automaticLayout: true,
                }}
              />
            </div>

            <div
              className="d_flex d_jcc aic"
              style={{ gap: "12px", margin: "20px 0 105px" }}
            >
              <button type="button" className="blu_btn" onClick={handlePrettify}>
                포맷(prettify)
              </button>
              <button type="button" className="blu_btn" onClick={handleSave}>
                저 장
              </button>
              <Link to={URL.ADMIN_CATALOG} className="blu_btn">
                목 록
              </Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EgovAdminCatalogEdit;

