import React, { useState, useEffect } from "react";

import { Link, useLocation, useNavigate } from "react-router-dom";

import * as EgovNet from "@/api/egovFetch";
import URL from "@/constants/url";
import CODE from "@/constants/code";
import { NOTICE_BBS_ID } from "@/config";

import { default as EgovLeftNav } from "@/components/leftmenu/EgovLeftNavAdmin";
import EgovAttachFile from "@/components/EgovAttachFile";

interface EgovAdminNoticeDetailProps {
  [key: string]: unknown;
}

interface NoticeLocationState {
  bbsId?: string;
  nttId?: string;
  searchCondition?: Record<string, unknown>;
}

interface MasterBoard {
  bbsNm?: string;
  fileAtchPosblAt?: string;
  bbsUseFlag?: string;
  replyPosblAt?: string;
}

interface BoardDetail {
  bbsId?: string;
  nttId?: string;
  nttSj?: string;
  ntcrNm?: string;
  frstRegisterPnttm?: string;
  inqireCo?: number | string;
  nttCn?: string;
  parnts?: string;
}

function EgovAdminNoticeDetail(props: EgovAdminNoticeDetailProps) {
  console.group("EgovAdminNoticeDetail");
  console.log("------------------------------");
  console.log("EgovAdminNoticeDetail [props] : ", props);

  const navigate = useNavigate();
  const location = useLocation();
  console.log("EgovAdminNoticeDetail [location] : ", location);

  const locationState = (location.state ?? {}) as NoticeLocationState;
  const bbsId = locationState.bbsId || NOTICE_BBS_ID;
  const nttId = locationState.nttId;
  const searchCondition = locationState.searchCondition;

  const [masterBoard, setMasterBoard] = useState<MasterBoard>({});
  const [boardDetail, setBoardDetail] = useState<BoardDetail>({});
  const [boardAttachFiles, setBoardAttachFiles] = useState<unknown[]>();

  const retrieveDetail = () => {
    const retrieveDetailURL = `/board/${bbsId}/${nttId}`;
    const requestOptions = {
      method: "GET",
      headers: {
        "Content-type": "application/json",
      },
    };
    EgovNet.requestFetch(retrieveDetailURL, requestOptions, function (resp: { result: { brdMstrVO: MasterBoard; boardVO: BoardDetail; resultFiles: unknown[] } }) {
      setMasterBoard(resp.result.brdMstrVO);
      setBoardDetail(resp.result.boardVO);
      setBoardAttachFiles(resp.result.resultFiles);
    });
  };

  const onClickDeleteBoardArticle = (bbsId?: string, nttId?: string) => {
